import '../base/Slider.base.scss';
import './MultiSlider.scss';

import { classNames } from ':helpers/classnames';
import { useComponentDidMount } from ':helpers/use-component-did-mount';
import type { ChangeEventHandler, FC, ReactNode } from 'react';
import React, { useCallback, useEffect, useMemo, useRef, useState } from 'react';

import { Typography } from '../../Typography';
import { range as calcRange } from '../range';
import type { MultiSliderProps } from './MultiSlider.types';

export const MultiSlider: FC<MultiSliderProps> = ({
	min = 0,
	max = 100,
	step = 1,
	showOptions = false,
	showLabel = false,
	value = [min, max],
	optionsStep,
	onChange,
	className,
	options,
	startAdornment,
	endAdornment,
	disabled,
	...props
}) => {
	const [minInitVal, maxInitVal] = value;
	const [minVal, setMinVal] = useState<number>(Math.max(minInitVal, min));
	const [maxVal, setMaxVal] = useState<number>(Math.min(maxInitVal, max));

	const minValRef = useRef<HTMLInputElement>(null);
	const maxValRef = useRef<HTMLInputElement>(null);
	const range = useRef<HTMLDivElement>(null);
	const isComponentMounted = useComponentDidMount();

	const getPercent = useCallback((value: number) => Math.round(((value - min) / (max - min)) * 100), [min, max]);

	useEffect(() => {
		setMinVal(minInitVal);
		setMaxVal(maxInitVal);
	}, [minInitVal, maxInitVal, min, max]);

	useEffect(() => {
		if (maxValRef.current) {
			const minPercent = getPercent(minVal);
			const maxPercent = getPercent(+maxValRef.current.value);

			if (range.current) {
				range.current.style.left = `${minPercent}%`;
				range.current.style.width = `${maxPercent - minPercent}%`;
			}
		}
	}, [minVal, getPercent]);

	useEffect(() => {
		if (minValRef.current) {
			const minPercent = getPercent(+minValRef.current.value);
			const maxPercent = getPercent(maxVal);

			if (range.current) {
				range.current.style.width = `${maxPercent - minPercent}%`;
			}
		}
	}, [maxVal, getPercent]);

	useEffect(() => {
		if (isComponentMounted) {
			onChange?.([minVal, maxVal]);
		}
	}, [minVal, maxVal, onChange, isComponentMounted]);

	const handleMinChange: ChangeEventHandler<HTMLInputElement> = event => {
		const value = Math.min(+event.target.value, maxVal - +step);
		setMinVal(value);
	};

	const handleMaxChange: ChangeEventHandler<HTMLInputElement> = event => {
		const value = Math.max(+event.target.value, minVal + +step);
		setMaxVal(value);
	};

	const handleOptionClick = (number: number): void => {
		if (typeof step !== 'number') {
			return;
		}

		const modulo = number % step;
		const halfStep = step / 2;

		if (modulo < halfStep) {
			if (number >= maxVal) {
				return setMaxVal(number - modulo);
			}
			return setMinVal(number - modulo);
		}
		if (number >= maxVal) {
			return setMaxVal(number + modulo);
		}
		return setMinVal(number + modulo);
	};

	// const allOptions = useMemo(() => calcRange(min, max), [min, max]);
	const targetOptions = useMemo(
		() => options || calcRange(min, max, optionsStep || step),
		[min, max, step, optionsStep, options],
	);

	return (
		<div
			data-testid="MultiSlider"
			className={classNames(
				'dsb_slider-container',
				'dsb_multi-slider-container',
				className,
				disabled && 'dsb_slider-container__disabled',
			)}
			aria-valuemax={max}
			aria-valuemin={min}
			aria-live="polite"
		>
			{startAdornment && (
				<div
					className={classNames(
						'dsb_slider-adornment',
						'dsb_slider-adornment--start',
						'dsb_slider-adornment--left',
						`dsb_slider-adornment--${startAdornment.position}`,
					)}
				>
					{startAdornment.content}
				</div>
			)}

			{endAdornment && (
				<div
					className={classNames(
						'dsb_slider-adornment',
						'dsb_slider-adornment--end',
						'dsb_slider-adornment--right',
						`dsb_slider-adornment--${endAdornment.position}`,
					)}
				>
					{endAdornment.content}
				</div>
			)}
			{showLabel && !disabled && (
				<div className="dsb_slider-value-track-wrapper">
					<div className="dsb_slider-value-track dsb_slider-min-value-track">
						<div
							style={{
								marginLeft: `${((minVal - min) * 100) / (max - min)}%`,
							}}
							className="dsb_slider-value-label-wrapper"
						>
							<Typography variant="caption" className="dsb_slider-value-label dsb_slider-min-value-label">
								{minVal}
							</Typography>
						</div>
					</div>
					<div className="dsb_slider-value-track dsb_slider-max-value-track">
						<div
							style={{
								marginLeft: `${((maxVal - min) * 100) / (max - min)}%`,
							}}
							className="dsb_slider-value-label-wrapper"
						>
							<Typography variant="caption" className="dsb_slider-value-label dsb_slider-max-value-label">
								{maxVal}
							</Typography>
						</div>
					</div>
				</div>
			)}
			<div className="dsb_multi-slider">
				<div className="dsb_slider-track" />
				<div ref={range} className="dsb-slider-range" />
				<input
					{...props}
					disabled={disabled}
					type="range"
					value={minVal}
					min={min}
					max={max}
					step={step}
					ref={minValRef}
					onChange={handleMinChange}
					className={classNames('dsb_slider-thumb dsb_slider_min-value', disabled && 'dsb_slider-thumb__disabled')}
				/>
				<input
					{...props}
					disabled={disabled}
					type="range"
					value={maxVal}
					min={min}
					max={max}
					step={step}
					ref={maxValRef}
					onChange={handleMaxChange}
					className={classNames('dsb_slider-thumb dsb_slider_max-value', disabled && 'dsb_slider-thumb__disabled')}
				/>
			</div>

			{showOptions && (
				<div className="dsb_slider-datalist">
					{targetOptions.map((number): ReactNode => {
						const isActive = number >= minVal && number <= maxVal;

						return (
							<Typography
								variant={isActive ? 'subtitle3' : 'body3'}
								key={number}
								onClick={(): void => handleOptionClick(number)}
								data-value={number}
								className={classNames('dsb_slider-option dsb_slider-option__fill', {
									'dsb_slider-option__active': isActive,
								})}
							>
								{number}
							</Typography>
						);
					})}
				</div>
			)}
		</div>
	);
};
